var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"야, 노엘…! 정신 차려……!","JPN":"ノエル……！　しっかりして……！","ENG":"Hey, Noelle...! Snap out of it...!","TWN":"喂，洛艾兒！振作點！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 왔어! 내가 널 구하러 왔단 말이야……!","JPN":"私が来た！　あなたを助けに来たんだよ……！","ENG":"I'm here! I came to save you...!","TWN":"我來了！我是來救你的！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 멍하니 있지 말고, 빨리 정신 차리라고……!","JPN":"だからぼーっとしてないで、早く正気に戻って……！","ENG":"So don't just sit there, wake up already...!","TWN":"所以，不要發呆，趕快振作起來！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"큭, 제기랄……!","JPN":"くっ、こんな……！","ENG":"Kgh, damn it...!","TWN":"呃，該死！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 짓이야, 스완! 노엘한테서 떨어져!","JPN":"何をするの、スワン！　ノエルから離れろ！","ENG":"What are you doing, Swan?! Get away from Noelle!","TWN":"你在幹什麼？史旺！離洛艾兒遠點！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇게 애타게 불러봐도 소용없답니다, 늑대.","JPN":"どれだけ懸命に呼びかけたって無駄です、オオカミ。","ENG":"You can cry out all you want, but it's useless, Wolf.","TWN":"就算你再怎麼焦急地呼喚也沒用，狼。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면 이 아이는 이미 정신이 망가져, 자아를 상실해 버렸으니까요.","JPN":"なぜならこの子はすでに精神が崩壊し、自我を失っていますから。","ENG":"Because this girl's mind is already shattered. She's lost all sense of self.","TWN":"因為這個孩子的精神已經崩潰，失去了自我。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이래서야 인간이 아니라, 곱상한 인형에 불과하군요.","JPN":"ふふ、これでは人間ではなく、ただの愛らしいお人形ですね。","ENG":"Haha, she's not human anymore. Just a pretty little doll.","TWN":"呵呵，這樣的話，不是人類，只不過是個漂亮的玩偶而已。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 살결이 제법 부드럽네요. 제 취향은 아니지만, 어디 조금은 가지고 놀아볼까요?","JPN":"まあ、なんて柔らかい肌。私の好みではないけれど、少しくらい遊んでみましょうか。","ENG":"Haha, her skin's soft. Not really my type, but maybe I'll play with her for a bit?","TWN":"呵呵，肌膚還挺柔軟的嘛。雖然不是我的菜，但要不要稍微玩玩呢？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"젠장, 그만둬! 그만두라고……!!","JPN":"くそ、やめろ！　やめろってば……！！","ENG":"Damn it, stop! I said stop...!!","TWN":"該死，住手！住手！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"보기보다 학습 능력이 없네요, 늑대. 소용없다고 했을 텐데요?","JPN":"案外学習能力が乏しいのですね、オオカミ。無駄だと言ったはずです。","ENG":"You really don't learn, do you, Wolf? I told you it's pointless.","TWN":"看起來你的學習能力不怎麼樣，狼。我不是說過沒用嗎？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Kgh...!","TWN":"呃！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 모습도, 목소리도 결코 이 아이에게 닿지 않는답니다.","JPN":"あなたの姿も、声も、決してこの子に届くことはありません。","ENG":"Your face, your voice. None of it will ever reach her.","TWN":"無論是你的樣子，還是聲音，都無法傳達到這個孩子那裡。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 아이는 그저 제가 머릿속에 심어둔 각본대로 이 세계를 재현하고 있을 뿐이니까요.","JPN":"この子はただ、私が頭の中に植え付けておいた脚本どおりにこの世界を再現しているだけですから。","ENG":"She's simply playing out the script I planted in her mind. Recreating this world exactly as I wrote it.","TWN":"這個孩子只是在按照我在她腦海中植入的劇本，重現這個世界而已。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 이제 곧, 이 세계가 멸망하는 순간을 그대로 재현해 내겠죠.","JPN":"そして間もなく、この世界が滅亡する瞬間をそのまま再現するでしょう。","ENG":"And soon, she'll recreate the moment this world meets its end.","TWN":"而現在，她將重現這個世界毀滅的瞬間。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 순간이 바로 이번 각본이 엔딩을 맞이하는 시점입니다.","JPN":"その瞬間こそが、今回の脚本のエンディングなのです。","ENG":"That moment will mark the end of this script.","TWN":"那個時刻正是這次劇本迎來結局的時刻。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"세계가 멸망하는 순간을 재현하겠다고……?","JPN":"世界が滅亡する瞬間を再現する……？","ENG":"Recreate the end of the world...?","TWN":"要重現世界毀滅的瞬間？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"설마……!","JPN":"まさか……！","ENG":"No way...!","TWN":"不會吧！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"젠장, 어째 시간을 끌고 있는 것 같더니만……!","JPN":"ちっ、なんか時間稼ぎしてるなと思ったら……！","ENG":"Damn it, so that's why you were stalling for time...!","TWN":"可惡，我說怎麼總感覺她在拖延時間！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시간을 끌어? 그게 무슨 소리야?","JPN":"時間稼ぎ？　どういうこと？","ENG":"Stalling? What do you mean?","TWN":"拖延時間？什麼意思？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 짐작한 대로라네, 미나 양.","JPN":"君の予測通りだよ、ミナ君。","ENG":"Just as you suspect, Mina.","TWN":"正如你所猜測的那樣，米娜。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완은 이 세계를 또다시 <color=#ffd34c>되풀이</color>할 생각이라네.","JPN":"スワンはまたしても、この世界を<color=#ffd34c>繰り返す</color>つもりだ。","ENG":"Swan intends to <color=#ffd34c>repeat</color> this world all over again.","TWN":"史旺打算再次<color=#ffd34c>重複</color>這個世界。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"되풀이라고?","JPN":"繰り返す？","ENG":"Repeat it?","TWN":"重複？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};